export function isHoliday(day) {
	const d = typeof day === 'string' ? new Date(day) : day
	const s = d.getFullYear() + '-' + (d.getMonth() + 1) + '-' + d.getDate()
	if (PUBLIC_HOLIDAYS.has(s)) return true
	const w = d.getDay()
	return w === 0 || w === 6
}

export function isPublicHoliday(day) {
	const d = typeof day === 'string' ? new Date(day) : day
	const s = d.getFullYear() + '-' + (d.getMonth() + 1) + '-' + d.getDate()
	return PUBLIC_HOLIDAYS.has(s)
}

export function getCalendarDays(y, m) {
  const first = new Date(y, m - 1, 1)
  const startDay = first.getDay()
  const res = []
  for (let i = 0; i < 42; i++) {
    const date = new Date(y, m - 1, i - startDay + 1)
    const dy = date.getFullYear()
    const dm = date.getMonth() + 1
    const d = date.getDate()
    const w = PUBLIC_HOLIDAYS.has(`${dy}-${dm}-${d}`) ? 7 : date.getDay() 
    res.push([dm === m ? 1 : 0, w, d])
  }
  return res
}
